// ── LOOKUP HELPERS ───────────────────────────────────────────────────────────

export function getExerciseById(id) {
  return EXERCISES.find(e => e.id === id) || null;
}

export function getExercisesByMuscle(muscle, environment = null) {
  return EXERCISES.filter(e => {
    const matchMuscle = e.muscle_primary === muscle || e.muscles_secondary.includes(muscle);
    const matchEnv = !environment || e.environment === environment || e.environment === 'no_equipment';
    return matchMuscle && matchEnv;
  });
}

export function getExercisesByEnvironment(environment) {
  if (environment === 'gym') return EXERCISES.filter(e => e.environment !== 'home' && e.environment !== 'no_equipment' || e.environment === 'no_equipment');
  if (environment === 'home') return EXERCISES.filter(e => e.environment === 'home' || e.environment === 'no_equipment');
  return EXERCISES.filter(e => e.environment === 'no_equipment');
}
